{
  "key": "tiered-infra-detection-decision-tree",
  "namespace": "dirigent-research",
  "value": {
    "topic": "Decision tree for tiered test infra detection and provisioning in Dirigent",
    "environment_tier_detection": {
      "tier_1_devbox": {
        "signal_files": [
          "devbox.json"
        ],
        "viability_check": "`devbox version 2>/dev/null` exits 0 (confirms nix is working)",
        "services_available": "check if any package in devbox.json packages array matches known service packages: postgresql, redis, valkey, mysql, mariadb",
        "init_required": "postgresql and mysql need initdb/mysqld init before first start",
        "start_command": "devbox services start (starts ALL services)",
        "health_check": "pg_isready or redis-cli ping",
        "ci_support": "YES via jetify-com/devbox-install-action@v0.14.0",
        "broken_devbox_fallback": "devbox binary present but `devbox version` fails → nix broken → skip to tier 2"
      },
      "tier_2_asdf_mise": {
        "signal_files": [
          ".tool-versions",
          "mise.toml",
          ".mise.toml",
          ".rtx.toml"
        ],
        "services_available": false,
        "notes": ".tool-versions/mise only manage tool VERSIONS (node, python, ruby). They do NOT provision databases or caches. This tier is environment-only, not services.",
        "action": "Read .tool-versions to know exact node/python/ruby version needed. Use `mise install` or `asdf install` to get correct version.",
        "command": "mise install 2>/dev/null || asdf install 2>/dev/null"
      },
      "tier_3_native": {
        "signal": "Neither devbox.json nor .tool-versions found",
        "action": "Check PATH for required tools. Read package.json engines field or .node-version or .nvmrc for version hints.",
        "services_available": false
      }
    },
    "services_tier_detection": {
      "tier_1_devbox_services": {
        "prerequisite": "devbox.json exists AND devbox version works",
        "detection": "packages array contains postgresql|redis|valkey|mysql|mariadb|mongodb",
        "action": "devbox services start [service_name]",
        "init_sequences": {
          "postgresql": [
            "devbox run initdb 2>/dev/null || devbox shell -- bash -c 'initdb 2>/dev/null || true'",
            "devbox services start postgresql",
            "createdb $DBNAME 2>/dev/null || true"
          ]
        },
        "confidence": "HIGH"
      },
      "tier_2_docker_compose": {
        "signal_files": [
          "docker-compose.yml",
          "docker-compose.yaml",
          "compose.yml",
          "compose.yaml",
          "compose.dev.yaml"
        ],
        "viability_check": "`docker info 2>/dev/null` exits 0",
        "action": "docker compose up -d [service_names]",
        "service_extraction": "parse services: block, get image name, ports, healthcheck, environment",
        "connection_string_from_environment_block": true,
        "confidence": "HIGH if Docker running, SKIP if Docker not available"
      },
      "tier_3_ci_extraction": {
        "signal_files": [
          ".github/workflows/*.yml",
          ".gitlab-ci.yml"
        ],
        "action": "Parse services: block as described in ci-config-extraction-patterns memory key",
        "output": "Connection string reconstructed from CI env vars + host ports",
        "confidence": "MEDIUM — CI services map 1:1 to local but values may differ"
      },
      "tier_4_in_process_mocks": {
        "detection": {
          "python": [
            "conftest.py imports sqlite3 or uses :memory:",
            "factory_boy in deps",
            "pytest-mock, responses, httpretty, respx in deps"
          ],
          "node": [
            "jest.mock patterns",
            "msw (mock service worker) in deps",
            "nock in deps",
            "jest-sqlite, better-sqlite3 used in tests"
          ]
        },
        "action": "Document that tests use mocks. Run tests as-is. Report infra_tier=4_mocked.",
        "confidence": "MEDIUM — unit tests valid, integration coverage absent"
      },
      "tier_5_generate_devbox": {
        "precondition": "No devbox.json, Docker not available or no compose file, no CI services",
        "action": "Generate devbox.json from detected stack (requires devbox CLI available and nix working)",
        "template_selection": {
          "postgres detected": "add postgresql@latest to packages",
          "redis detected": "add redis@latest to packages",
          "node detected": "add nodejs@<version> based on .nvmrc or engines field",
          "python detected": "add python@<version> from pyproject.toml python_requires"
        },
        "write_path": "devbox.json at repo root",
        "then_run": "tier_1_sequence"
      },
      "tier_6_generate_docker_compose": {
        "precondition": "Cannot use devbox (nix broken), no existing compose, Docker IS available",
        "action": "Generate minimal docker-compose.yml with detected services",
        "template": "services:\n  postgres:\n    image: postgres:15-alpine\n    environment:\n      POSTGRES_PASSWORD: devpass\n      POSTGRES_DB: appdb\n    ports:\n      - '5432:5432'\n    healthcheck:\n      test: pg_isready\n      interval: 5s",
        "confidence": "HIGH if Docker available"
      },
      "tier_7_gap_report": {
        "precondition": "All tiers failed",
        "action": "Write .dirigent/INFRA_GAPS.json",
        "schema": {
          "gaps": [
            {
              "service": "postgres",
              "reason": "no devbox.json, no docker-compose.yml, docker not available, no CI config with services",
              "impact": "integration tests cannot run",
              "mitigation": "tests will use SQLite if available, else mark as infra_missing"
            },
            {
              "service": "redis",
              "reason": "same as above",
              "impact": "cache-dependent code paths untested"
            }
          ],
          "test_confidence": "low",
          "recommended_action": "Add docker-compose.yml or devbox.json with required services"
        }
      }
    },
    "implementation_note": "The detection logic belongs in init_phase.py as a new InfraDetector class. It should run before the existing init script check and produce a structured InfraContext that is added to the TestHarness under a new 'infra_tier' field."
  },
  "tags": [
    "decision-tree",
    "detection",
    "provisioning",
    "init-phase",
    "tiers",
    "implementation"
  ],
  "storedAt": 1774971261900,
  "updatedAt": 1774971261900,
  "accessCount": 1,
  "hasEmbedding": true,
  "found": true,
  "backend": "sql.js + HNSW"
}

