{
  "key": "autonomous-agent-test-infra-landscape",
  "namespace": "dirigent-research",
  "value": {
    "topic": "How autonomous coding agents handle test infrastructure — competitive landscape",
    "agents": {
      "devin": {
        "approach": "Full cloud VM per task — Devin provisions a dedicated VM snapshot with docker pre-installed. Runs docker-compose up as standard step. Does NOT use devbox or nix.",
        "test_infra": "Runs the project's existing docker-compose. If none exists, Devin attempts to install deps natively. No auto-generation of docker-compose.",
        "progressive_verification": "Devin re-runs tests after each major change. Uses task-level acceptance criteria from the issue.",
        "key_insight": "Persistent VM means services stay up across the session. No infra re-provisioning needed mid-session."
      },
      "openhands": {
        "approach": "Docker container sandbox. Default OpenHands runtime has Docker-in-Docker support. Can run docker-compose inside the sandbox.",
        "test_infra": "Uses existing docker-compose if present. The SWE-bench evaluator pre-provisions environments. For general tasks, services may not start.",
        "key_insight": "OpenHands does NOT auto-detect or provision test infra. Relies on pre-existing setup scripts.",
        "source": "github.com/All-Hands-AI/OpenHands"
      },
      "swe_agent": {
        "approach": "Docker containers via SWE-bench benchmark. Each instance is a pre-baked container with the repo + dependencies already installed.",
        "test_infra": "All infra is pre-provisioned in the container image. SWE-agent just runs `python -m pytest` — no service management.",
        "key_insight": "SWE-bench cheats — the benchmark pre-bakes environments. SWE-agent itself has no infra provisioning."
      },
      "aider": {
        "approach": "Runs locally in the developer's environment. No sandboxing, no infra provisioning.",
        "test_infra": "Aider expects the developer to have services already running. It can run git diff and linting but not start services.",
        "key_insight": "Purely code-edit focused. Infra is the developer's responsibility."
      },
      "cursor_agent": {
        "approach": "Runs in developer's local environment via the Cursor IDE. Uses existing terminal.",
        "test_infra": "Can run commands in the developer's existing environment. No auto-provisioning. Relies on whatever is running."
      },
      "codex_openai": {
        "approach": "Cloud sandbox. OpenAI Codex agent provisions containers for each task.",
        "test_infra": "Pre-installs deps via install step. Limited service management."
      },
      "state_of_art_summary": "NO current autonomous agent auto-detects and provisions test infra from scratch. The state of the art is: (1) require pre-existing scripts, (2) use cloud VMs where docker-compose just works, or (3) use pre-baked benchmark containers. Dirigent's tiered provisioning system would be industry-leading."
    },
    "progressive_verification_patterns": {
      "concept": "Run subset of tests after each task rather than full suite. Escalate scope if early tests pass.",
      "implementations_found": [
        "SWE-bench runs `python -m pytest <specific_test_file>` for targeted verification",
        "Devin runs acceptance criteria checks between tasks"
      ],
      "confidence_annotation": {
        "concept": "Tag test results with confidence level based on infra completeness",
        "proposed_schema": {
          "test_result": "pass|fail|skip",
          "confidence": "high|medium|low|infra_missing",
          "infra_tier_used": "1_devbox|2_docker_compose|3_ci_extracted|4_mocked|5_generated",
          "caveat": "Tests passed with mocked Redis — real Redis behavior untested"
        }
      }
    },
    "recommended_approach_for_dirigent": {
      "insight": "Dirigent should be the FIRST agent to implement tiered test infra detection+provisioning",
      "competitive_advantage": "Report infra tier used + confidence annotation in test results. Other agents give binary pass/fail. Dirigent gives contextual results.",
      "key_differentiator": "INFRA_GAPS.json — machine-readable record of what infra gaps exist and why tests ran at degraded confidence"
    }
  },
  "tags": [
    "competitive-landscape",
    "devin",
    "openhands",
    "swe-agent",
    "aider",
    "autonomous-agents",
    "progressive-verification"
  ],
