{
  "key": "test-data-seeding-patterns",
  "namespace": "dirigent-research",
  "value": {
    "topic": "Test data seeding detection and patterns by stack",
    "detection_priority": "Check in this order: (1) package.json scripts for db:seed/seed keys, (2) prisma/seed.ts or prisma/seed.js existence, (3) knex seeds/ directory, (4) Python conftest.py with @pytest.fixture for db/session, (5) factory_boy factories.py, (6) Django fixtures/ .json/.yaml files, (7) Ruby db/seeds.rb or spec/factories/, (8) Go testcontainers in *_test.go",
    "node_typescript": {
      "prisma": {
        "detection": [
          "prisma/seed.ts or prisma/seed.js exists",
          "package.json has prisma.seed key: 'ts-node prisma/seed.ts'"
        ],
        "run_command": "npx prisma db seed",
        "health_check": "after `npx prisma migrate dev`, check DATABASE_URL connectivity",
        "connection_string_source": "DATABASE_URL in .env",
        "notes": "Prisma seed uses @prisma/client directly, creates records programmatically. Very reliable detection."
      },
      "knex": {
        "detection": [
          "knex.js or knexfile.js/ts at root or config/",
          "seeds/ directory with *.js or *.ts files",
          "package.json scripts containing 'knex seed'"
        ],
        "run_command": "npx knex seed:run",
        "notes": "Knex seeds are idempotent when written correctly. Often found alongside db:migrate = 'knex migrate:latest'."
      },
      "fixtures_json": {
        "detection": [
          "__fixtures__/ or fixtures/ directory with .json files",
          "test setup importing from fixtures/ path"
        ],
        "usage": "jest.mock or direct import, no DB needed for these"
      },
      "drizzle": {
        "detection": [
          "drizzle.config.ts exists",
          "package.json scripts containing 'drizzle-kit'"
        ],
        "seed": "typically a custom scripts/seed.ts run via ts-node or tsx",
        "notes": "No built-in seed command, look for seed script in package.json"
      }
    },
    "python": {
      "pytest_fixtures": {
        "detection": [
          "conftest.py exists at tests/ or root",
          "fixtures using SQLite :memory: or tmp file engine"
        ],
        "real_pattern": "engine = create_engine('sqlite:///:memory:'); SQLModel.metadata.create_all(engine) — no external DB needed",
        "async_pattern": "engine = create_async_engine('sqlite+aiosqlite:///:memory:')",
        "notes": "SQLite in-memory is the dominant Python unit test pattern — zero infra requirement. Integration tests use real DB via env var."
      },
      "factory_boy": {
        "detection": [
          "factory_boy in requirements.txt or pyproject.toml",
          "factories.py or test/factories.py or tests/factories/ dir"
        ],
        "example": "class UserFactory(factory.django.DjangoModelFactory): class Meta: model = User",
        "notes": "factory_boy generates objects without needing seed scripts. Often paired with pytest-factoryboy."
      },
      "django_fixtures": {
        "detection": [
          "fixtures/ directories containing .json or .yaml files",
          "python manage.py loaddata <fixture> in Makefile/scripts",
          "INSTALLED_APPS or settings.py has fixture path"
        ],
        "run_command": "python manage.py loaddata fixtures/initial_data.json",
        "create_fixture": "python manage.py dumpdata auth.User > fixtures/users.json"
      },
      "alembic_seed": {
        "detection": [
          "alembic.ini at root",
          "no dedicated seed script — migrations may include data inserts in upgrade()"
        ],
        "notes": "Many Python projects have no seed script — tests create data via factories or conftest fixtures"
      }
    },
    "ruby": {
      "db_seed": {
        "detection": [
          "db/seeds.rb exists"
        ],
        "run_command": "rails db:seed or bundle exec rails db:seed",
        "notes": "Standard Rails pattern, universally present"
      },
      "factory_bot": {
        "detection": [
          "factory_bot or factory_bot_rails in Gemfile",
          "spec/factories/ directory"
        ],
