{
  "key": "ci-config-extraction-patterns",
  "namespace": "dirigent-research",
  "value": {
    "topic": "CI config extraction for services tier (tier 3)",
    "github_actions_services_schema": {
      "location": "jobs.<job>.services.<service_name>",
      "fields": {
        "image": "Docker image string, e.g. postgres:15 — extract name from this",
        "env": "dict of env vars — POSTGRES_USER, POSTGRES_PASSWORD, POSTGRES_DB, POSTGRES_HOST_AUTH_METHOD",
        "ports": "list of 'host_port:container_port' strings",
        "options": "string of --health-cmd, --health-interval, --health-timeout, --health-retries docker flags"
      },
      "real_postgres_example": {
        "image": "postgres:15",
        "env": {
          "POSTGRES_USER": "testuser",
          "POSTGRES_PASSWORD": "testpass",
          "POSTGRES_DB": "testdb"
        },
        "ports": [
          "5432:5432"
        ],
        "options": "--health-cmd pg_isready --health-interval 10s --health-timeout 5s --health-retries 5"
      },
      "real_redis_example": {
        "image": "redis:7",
        "ports": [
          "6379:6379"
        ],
        "options": "--health-cmd \"redis-cli ping\" --health-interval 10s --health-timeout 5s --health-retries 5"
      }
    },
    "extraction_algorithm": {
      "step1": "glob .github/workflows/*.yml (also .yaml)",
      "step2": "yaml.safe_load each file",
      "step3": "for each job in data.get('jobs',{}).values(): for svc_name, svc in job.get('services',{}).items()",
      "step4": "extract image name: svc['image'].split(':')[0].split('/')[-1] → normalizes 'bitnami/postgresql' → 'postgresql'",
      "step5": "extract host port: svc.get('ports',[]) → parse 'host:container' string",
      "step6": "extract connection env: look for POSTGRES_USER/PASSWORD/DB, MYSQL_ROOT_PASSWORD, REDIS_URL patterns in svc.get('env',{})",
      "step7": "also check job-level env and steps env blocks for DATABASE_URL, REDIS_URL overrides",
      "caveat": "CONNECTION_STRING reconstruction: never trust CI env values as-is for local — ports may differ, hosts are always localhost in CI runners"
    },
    "service_name_normalization": {
      "postgres:15": "postgres",
      "bitnami/postgresql:14": "postgres",
      "redis:7-alpine": "redis",
      "mysql:8": "mysql",
      "mongo:7": "mongodb",
      "elasticsearch:8.11.0": "elasticsearch",
      "rabbitmq:3-management": "rabbitmq"
    },
    "local_connection_reconstruction": {
      "postgres": "DATABASE_URL=postgresql://${POSTGRES_USER:-postgres}:${POSTGRES_PASSWORD:-postgres}@localhost:${host_port:-5432}/${POSTGRES_DB:-postgres}",
      "redis": "REDIS_URL=redis://localhost:${host_port:-6379}",
      "mysql": "DATABASE_URL=mysql://${MYSQL_USER:-root}:${MYSQL_ROOT_PASSWORD}@localhost:${host_port:-3306}/${MYSQL_DATABASE}",
      "mongodb": "MONGODB_URL=mongodb://localhost:${host_port:-27017}"
    },
    "other_ci_formats": {
      "gitlab_ci": "services: block at job level, image: postgres:15 with aliases",
      "circleci": "executors or docker: [{image: ...}] with environment block",
      "all_use_same_concept": "a docker image + env vars + port mapping"
    }
  },
  "tags": [
    "ci",
    "github-actions",
    "services",
    "postgres",
    "redis",
    "yaml-parsing",
    "tier-3"
  ],
