  "key": "devbox-capabilities-deep-dive",
  "namespace": "dirigent-research",
  "value": {
    "topic": "Devbox capabilities for tiered test infra provisioning",
    "version_observed": "0.17.0",
    "nix_dependency": "CRITICAL — devbox requires nix binary in PATH. If broken, all devbox commands fail. Detection: check `which devbox` AND `devbox version` (not just existence).",
    "ci_viability": {
      "verdict": "YES — viable in CI via jetify-com/devbox-install-action GitHub Action",
      "action": "uses: jetify-com/devbox-install-action@v0.14.0",
      "caveat": "devbox-install-action installs nix + devbox together. Without this action, devbox in CI is unreliable if nix is missing from PATH.",
      "headless_detection": "Run `devbox version 2>/dev/null && echo ok || echo broken` — exit 0 means working nix+devbox stack"
    },
    "services_mechanism": {
      "backend": "process-compose (lightweight process manager, separate binary)",
      "how_it_works": "devbox services up|start|stop delegates to a per-project process-compose.yaml in .devbox/virtenv/<pkg>/process-compose.yaml",
      "process_compose_not_installed": "process-compose is a separate binary devbox installs automatically when you add a package with a services plugin"
    },
    "built_in_service_plugins": {
      "postgresql": {
        "package": "postgresql",
        "env_vars_set": [
          "PGDATA=.devbox/virtenv/postgresql/data",
          "PGHOST=<virtenv_path>"
        ],
        "process_compose": "postgres -k $PGHOST -p ${PGPORT:-5432}",
        "readiness_probe": "pg_isready -p ${PGPORT:-5432}",
        "shutdown": "pg_ctl stop -m fast",
        "init_required": "YES — must run `initdb` before first `devbox services start`",
        "port_override": "set PGPORT env var in devbox.json env block"
      },
      "redis": {
        "package": "redis",
        "env_vars_set": [
          "REDIS_PORT=6379",
          "REDIS_CONF=<devbox_dir>/redis.conf"
        ],
        "process_compose": "redis-server $REDIS_CONF --port $REDIS_PORT",
        "readiness": "on_failure restart with max_restarts=5",
        "no_init_required": true
      },
      "valkey": {
        "package": "valkey",
        "note": "Redis-compatible fork, same pattern as redis"
      },
      "mysql": {
        "package": "mariadb or mysql",
        "init_required": "YES — similar to postgres"
      }
    },
    "devbox_does_NOT_do": [
      "Auto-detect from package.json or requirements.txt — NO `devbox generate` from deps",
      "devbox generate only produces: devcontainer, dockerfile, direnv, readme, alias",
      "devbox create --template requires explicit template name, no auto-detection"
    ],
    "auto_provision_constraint": "Dirigent must detect the stack first, then WRITE devbox.json — devbox cannot infer it",
    "postgres_init_sequence": [
      "devbox shell -- initdb",
      "devbox services start postgresql",
      "createdb <dbname>",
      "psql <dbname> -f seed.sql  (or run migrations)"
    ],
    "devbox_json_nextjs_postgres_example": {
      "description": "Next.js + Postgres devbox.json",
      "json": {
        "$schema": "https://raw.githubusercontent.com/jetify-com/devbox/0.17.0/.schema/devbox.schema.json",
        "packages": [
          "nodejs@22",
          "pnpm@latest",
          "postgresql@latest"
        ],
        "env": {
          "PGPORT": "5432",
          "PGHOST": "/tmp/devbox/app",
          "DATABASE_URL": "postgresql://postgres@localhost:5432/appdb"
        },
        "shell": {
          "init_hook": [
            "mkdir -p $PGHOST",
            "initdb 2>/dev/null || true"
          ],
          "scripts": {
            "setup": [
              "devbox services start postgresql",
              "createdb appdb 2>/dev/null || true",
              "pnpm install",
              "pnpm run db:migrate"
            ],
            "dev": [
              "devbox services start postgresql",
              "pnpm run dev"
            ],
            "test": [
              "devbox services start postgresql",
              "pnpm test"
            ]
          }
        }
      }
    },
    "devbox_json_fastapi_redis_example": {
      "description": "Python FastAPI + Redis devbox.json",
      "json": {
